import React, { useState } from "react";
import { Link } from "react-router-dom";
import "../styles/News.css";
import ReadMore from "./ReadMore";  // Import ReadMore component
import NewsCard from "./NewsCard"; // Import the new NewsCard component

const articles = [
  // Your article data here...
];

const News = () => {
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [selectedArticle, setSelectedArticle] = useState(null);

  const openModal = (article) => {
    setSelectedArticle(article);
    setIsModalOpen(true);
  };

  const closeModal = () => {
    setIsModalOpen(false);
    setSelectedArticle(null);
  };

  return (
    <div className="News">
      <h2>News & Articles</h2>
      <div className="news-container">
        {articles.map((article) => (
          <NewsCard
            key={article.id}
            article={article}
            onReadMoreClick={openModal}
          />
        ))}
      </div>
      <Link to="/news" className="view-more">
        View more →
      </Link>

      {isModalOpen && selectedArticle && (
        <ReadMore selectedArticle={selectedArticle} closeModal={closeModal} />
      )}
    </div>
  );
};

export default News;
